    95	  const applyLetterEditing: CharacterEditingApplier = (params) => {
    96	    const findMatchingOptions = (
    97	      format: string,
    98	      options: string[],
    99	      queryValue: string,
   100	    ): ReturnType<QueryApplier<TValue>> => {
