   254	    const getFirstSectionValueMatchingWithQuery: QueryApplier<TValue> = (
   255	      queryValue,
   256	      activeSection,
   257	    ) => {
   258	      if (
   259	        activeSection.contentType === 'digit' ||
   260	        activeSection.contentType === 'digit-with-letter'
