   371	/**
   372	 * The letter editing and the numeric editing each define a `CharacterEditingApplier`.
   373	 * This function decides what the new section value should be and if the focus should switch to the next section.
   374	 *
   375	 * If it returns `null`, then the section value is not updated and the focus does not move.
   376	 */
   377	type CharacterEditingApplier = (
   378	  params: ApplyCharacterEditingParameters,
   379	) => { sectionValue: string; shouldGoToNextSection: boolean } | null;
