   381	/**
   382	 * Function called by `applyQuery` which decides:
   383	 * - what is the new section value ?
   384	 * - should the query used to get this value be stored for the next key press ?
   385	 *
   386	 * If it returns `{ sectionValue: string; shouldGoToNextSection: boolean }`,
   387	 * Then we store the query and update the section with the new value.
   388	 *
   389	 * If it returns `{ saveQuery: true` },
   390	 * Then we store the query and don't update the section.
   391	 *
   392	 * If it returns `{ saveQuery: false },
   393	 * Then we do nothing.
   394	 */
   395	type QueryApplier<TValue extends PickerValidValue> = (
   396	  queryValue: string,
   397	  activeSection: InferFieldSection<TValue>,
   398	) => { sectionValue: string; shouldGoToNextSection: boolean } | { saveQuery: boolean };
