    22	export const getDateSectionConfigFromFormatToken = (
    23	  adapter: MuiPickersAdapter,
    24	  formatToken: string,
    25	): Pick<FieldSection, 'type' | 'contentType'> & { maxLength: number | undefined } => {
    26	  const config = adapter.formatTokenMap[formatToken];
    27	
    28	  if (config == null) {
    29	    throw new Error(
    30	      `MUI X: The token "${formatToken}" is not supported by the Date and Time Pickers.
    31	Please try using another token or open an issue on https://github.com/mui/mui-x/issues/new/choose if you think it should be supported.`,
    32	    );
    33	  }
    34	
    35	  if (typeof config === 'string') {
    36	    return {
    37	      type: config,
    38	      contentType: config === 'meridiem' ? 'letter' : 'digit',
    39	      maxLength: undefined,
    40	    };
    41	  }
    42	
    43	  return {
    44	    type: config.sectionType,
    45	    contentType: config.contentType,
    46	    maxLength: config.maxLength,
    47	  };
    48	};
