    50	export const getDaysInWeekStr = (adapter: MuiPickersAdapter, format: string) => {
    51	  const elements: PickerValidDate[] = [];
    52	
    53	  const now = adapter.date(undefined, 'default');
    54	  const startDate = adapter.startOfWeek(now);
    55	  const endDate = adapter.endOfWeek(now);
    56	
    57	  let current = startDate;
    58	  while (adapter.isBefore(current, endDate)) {
    59	    elements.push(current);
    60	    current = adapter.addDays(current, 1);
    61	  }
    62	
    63	  return elements.map((weekDay) => adapter.formatByString(weekDay, format));
    64	};
