   118	export const removeLocalizedDigits = (valueStr: string, localizedDigits: string[]) => {
   119	  if (localizedDigits[0] === '0') {
   120	    return valueStr;
   121	  }
   122	
   123	  const digits: string[] = [];
   124	  let currentFormattedDigit = '';
   125	  for (let i = 0; i < valueStr.length; i += 1) {
