import { addHours } from 'date-fns/addHours';
import { setHours } from 'date-fns/setHours';

// Simulate what happens on March 8 (DST spring forward in US)
// Create a date at 12:00 PM (noon) on March 8, 2026 in America/New_York
const noonMar8 = new Date(2026, 2, 8, 12, 0, 0); // March 8, 2026, 12:00 PM

console.log('Starting date (12:00 PM March 8):', noonMar8.toString());
console.log('Hours:', noonMar8.getHours());
console.log('ISO:', noonMar8.toISOString());

// This is what the current buggy code does: addHours(date, -12)
const usingAddHours = addHours(noonMar8, -12);
console.log('\nUsing addHours(-12):');
